def lengthOfLongestSubstringKDistinct(s, k):
    m, l, res = collections.defaultdict(int), 0, 0
    for r, char in enumerate(s):
        m[char] += 1
        while len(m) > k:
            m[s[l]] -= 1
            if m[s[l]] == 0: del m[s[l]]
            l += 1
        res = max(res, r-l+1)
    return res

